def parcours_largeur(graphe, depart):
    visites = [depart]
    file = [depart]
    while file:
        noeud = file.pop(0)
        for voisin in graphe[noeud]:
            if voisin not in visites:
                visites.append(voisin)
                file.append(voisin)
    return visites

def parcours_profondeur(graphe, depart):
    visites = []

    def visiter(noeud):
        if noeud in visites:
            return
        visites.append(noeud)
        for voisin in graphe[noeud]:
            visiter(voisin)

    visiter(depart)
    return visites

import heapq

def plus_court_chemin(graphe, depart, arrivee):
    distances = {depart: 0}
    file = [(0, depart)]
    valides = set()
    while file:
        distance, noeud = heapq.heappop(file)
        if noeud in valides:
            continue
        valides.add(noeud)
        if noeud == arrivee:
            return distance
        for voisin, poids in graphe.get(noeud, []):
            nouvelle_distance = distance + poids
            if voisin not in distances or nouvelle_distance < distances[voisin]:
                distances[voisin] = nouvelle_distance
                heapq.heappush(file, (nouvelle_distance, voisin))
    return None

def contient_cycle(graphe):
    visites = set()

    def parcourir(noeud, parent):
        visites.add(noeud)
        for voisin in graphe[noeud]:
            if voisin not in visites:
                if parcourir(voisin, noeud):
                    return True
            elif voisin != parent:
                return True
        return False

    for depart in graphe:
        if depart not in visites:
            if parcourir(depart, None):
                return True
    return False

def est_connexe(graphe):
    depart = next(iter(graphe))
    visites = {depart}
    file = [depart]
    while file:
        noeud = file.pop(0)
        for voisin in graphe[noeud]:
            if voisin not in visites:
                visites.add(voisin)
                file.append(voisin)
    return len(visites) == len(graphe)
